output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?attendance WHERE {
  {
    ?series wdt:P31 wd:Q279014 ; wdt:P585 "1975" ^^ xsd:gYear .
    ?game wdt:P2994 ?series ; wdt:P1815 wd:Q203 ; wdt:P199 ?attendance .
    FILTER(datatype(?attendance) = xsd:integer)
  } UNION {
    ?series wdt:P31 wd:Q279014 ; wdt:P585 "2013" ^^ xsd:gYear .
    ?game wdt:P2994 ?series ; wdt:P1815 wd:Q203 ; wdt:P199 ?attendance .
    FILTER(datatype(?attendance) = xsd:integer)
  } UNION {
    ?series wdt:P31 wd:Q8440 ; wdt:P585 "2018" ^^ xsd:gYear .
    ?game wdt:P2994 ?series ; wdt:P1815 wd:Q203 ; wdt:P199 ?attendance .
    FILTER(datatype(?attendance) = xsd:integer)
  }
}
ORDER BY ?attendance
OFFSET 1
LIMIT 1

